8	import Foundation
9	
10	extension Float {
11	    var formattedValue: String {
12	        switch self {
13	        case 0..<10:
14	            String.localizedStringWithFormat("%.2f", self)
15	        case 10..<100:
16	            String.localizedStringWithFormat("%.1f", self)
17	        case 100..<1000:
18	            "\(Int(self))"
19	        case 1000..<10_000:
20	            String(localized: .Localization.formattedThousandDouble(floor(self / 1000 * 10) / 10))
21	        case 10_000..<1_000_000:
22	            String(localized: .Localization.formattedThousandInt(Int(self / 1000)))
23	        case 1_000_000...Double.infinity:
